-- file: views/leaderboard_season_totals.sql
-- One row per user per season with totals + ranks
create or replace view public.leaderboard_season_totals as
with season_rows as (
select
ps.user_id,
u.display_name,
s.year as season_year,
ps.points_delta,
ps.outcome
from public.pick_settlement ps
join public.games g on g.id = ps.game_id
join public.weeks w on w.id = g.week_id
join public.seasons s on s.id = w.season_id
join public.users u on u.id = ps.user_id
)
, totals as (
select
user_id,
display_name,
season_year,
sum(points_delta)::int as total_points,
count(*)::int as decisions,
count(*) filter (where outcome = 'win')::int as wins,
count(*) filter (where outcome = 'loss')::int as losses,
count(*) filter (where outcome = 'push')::int as pushes,
count(*) filter (where outcome = 'missed')::int as missed
from season_rows
group by user_id, display_name, season_year
)
select
t.*,
dense_rank() over (
partition by season_year
order by total_points desc, wins desc, pushes desc
) as rank
from totals t;

-- file: views/leaderboard_weekly_cumulative.sql
-- One row per user per (season, week) with week points and running total
create or replace view public.leaderboard_weekly_cumulative as
with week_rows as (
  select
    ps.user_id,
    u.display_name,
    s.year as season_year,
    w.week_number,
    sum(ps.points_delta)::int as week_points,
    count(*) filter (where ps.outcome = 'win')::int   as week_wins,
    count(*) filter (where ps.outcome = 'loss')::int  as week_losses,
    count(*) filter (where ps.outcome = 'push')::int  as week_pushes,
    count(*) filter (where ps.outcome = 'missed')::int as week_missed
  from public.pick_settlement ps
  join public.games   g on g.id = ps.game_id
  join public.weeks   w on w.id = g.week_id
  join public.seasons s on s.id = w.season_id
  join public.users   u on u.id = ps.user_id
  group by ps.user_id, u.display_name, s.year, w.week_number
),
cum as (
  select
    week_rows.*,
    -- running total per (user, season) ordered by week
    sum(week_points) over (
      partition by user_id, season_year
      order by week_number
      rows between unbounded preceding and current row
    )::int as cumulative_points
  from week_rows
)
select
  cum.*,
  -- season total per (user, season)
  sum(week_points) over (
    partition by user_id, season_year
  )::int as season_total,
  -- now we can safely rank by the precomputed column
  dense_rank() over (
    partition by season_year, week_number
    order by cum.cumulative_points desc
  ) as cumulative_rank_this_week
from cum;

-- file: functions/_private/ats_margin_at_lock.sql
create or replace function public.ats_margin_at_lock(
  home_pts int,
  away_pts int,
  home_id int,
  away_id int,
  spread_team_id int,
  spread_value numeric
) returns numeric
language sql
immutable
as $$
  select (home_pts - away_pts)
       + case
           when spread_team_id = home_id then spread_value
           when spread_team_id = away_id then -spread_value
           else 0
         end
$$;

-- file: functions/_private/game_has_started.sql
-- Helper: has the game started?
create or replace function public.game_has_started(p_game_id uuid)
returns boolean
language sql
stable
as $$
  select (now() >= g.commence_time) from public.games g where g.id = p_game_id
$$;

-- file: functions/_private/resolve_missed_penalty.sql
create or replace function public.resolve_missed_penalty_for_game(p_game_id uuid)
returns int
language sql
stable
set search_path = public
as $$
  select coalesce(w.missed_pick_penalty, s.missed_pick_penalty, st.missed_pick_penalty, -1)
  from public.games g
  join public.weeks   w  on w.id = g.week_id
  join public.seasons s  on s.id = w.season_id
  cross join public.settings st
  where g.id = p_game_id
  limit 1
$$;

-- file: functions/_private/weight_points.sql
create or replace function public.weight_points(p_weight text)
returns int
language sql
immutable
as $$
  select case upper(p_weight)
    when 'L' then 1 when 'M' then 3 when 'H' then 5 when 'A' then 10 else 0 end
$$;

-- file: functions/grade/grade_game.sql
create or replace function public.grade_game(p_game_id uuid)
returns void
language plpgsql
security definer
set search_path = public
as $$
declare
  home_pts int; away_pts int; home_id int; away_id int;
  v_penalty int;
begin
  select (final_scores->>'home')::int,
         (final_scores->>'away')::int,
         home_team_id, away_team_id
  into   home_pts, away_pts, home_id, away_id
  from public.games
  where id = p_game_id;

  if home_pts is null or away_pts is null then
    raise exception 'grade_game: game % has no final scores', p_game_id;
  end if;

  v_penalty := public.resolve_missed_penalty_for_game(p_game_id);

  -- (1) Upsert settlements for users who DID make a pick
  insert into public.pick_settlement (user_id, game_id, pick_id, points_delta, outcome, graded_at)
  select
    p.user_id,
    p.game_id,
    p.id,
    gp.points_delta,
    gp.outcome,
    now()
  from public.picks p
  cross join lateral public.grade_pick(
    home_pts, away_pts, home_id, away_id,
    p.picked_team_id, p.spread_team_id_at_lock, p.spread_value_at_lock, p.weight
  ) as gp
  where p.game_id = p_game_id
  on conflict (user_id, game_id)
  do update set
    pick_id      = excluded.pick_id,
    points_delta = excluded.points_delta,
    outcome      = excluded.outcome,
    graded_at    = excluded.graded_at;

  -- (2) Insert penalty rows for users with NO pick on this game
  insert into public.pick_settlement (user_id, game_id, pick_id, points_delta, outcome, graded_at)
  select
    u.id,
    p_game_id,
    null,
    v_penalty,
    'missed'::public.pick_outcome,
    now()
  from public.users u
  where u.role = 'player'
    and not exists (
      select 1 from public.picks p where p.game_id = p_game_id and p.user_id = u.id
    )
  on conflict (user_id, game_id)
  do update set
    -- only overwrite if there still isn't a pick (keeps idempotency & retro-pick overwrite correct)
    pick_id      = case when pick_settlement.pick_id is null then excluded.pick_id else pick_settlement.pick_id end,
    points_delta = case when pick_settlement.pick_id is null then excluded.points_delta else pick_settlement.points_delta end,
    outcome      = case when pick_settlement.pick_id is null then excluded.outcome else pick_settlement.outcome end,
    graded_at    = case when pick_settlement.pick_id is null then excluded.graded_at else pick_settlement.graded_at end;
end;
$$;

-- file: functions/grade/grade_pick.sql
create or replace function public.grade_pick(
  home_pts int,
  away_pts int,
  home_id int,
  away_id int,
  picked_team_id int,
  spread_team_id int,
  spread_value numeric,
  weight text
) returns table(points_delta int, outcome public.pick_outcome)
language sql
immutable
as $$
  with m as (
    select public.ats_margin_at_lock(home_pts, away_pts, home_id, away_id, spread_team_id, spread_value) as margin,
           public.weight_points(weight) as w
  )
  select
    case
      when margin = 0 then 0
      when margin > 0 then case when picked_team_id = home_id then w else -w end
      else                    case when picked_team_id = away_id then w else -w end
    end as points_delta,
    case
      when margin = 0 then 'push'::public.pick_outcome
      when margin > 0 then case when picked_team_id = home_id then 'win'::public.pick_outcome else 'loss'::public.pick_outcome end
      else                    case when picked_team_id = away_id then 'win'::public.pick_outcome else 'loss'::public.pick_outcome end
    end as outcome
  from m
$$;

-- file: functions/grade/grade_season.sql
create or replace function public.grade_season(p_season_id int)
returns void
language plpgsql
security definer
set search_path = public
as $$
begin
  -- (1) Real picks on final games
  insert into public.pick_settlement (user_id, game_id, pick_id, points_delta, outcome, graded_at)
  select
    p.user_id,
    g.id,
    p.id,
    gp.points_delta,
    gp.outcome,
    now()
  from public.weeks   w
  join public.games   g on g.week_id = w.id
  join public.picks   p on p.game_id = g.id
  cross join lateral public.grade_pick(
    (g.final_scores->>'home')::int,
    (g.final_scores->>'away')::int,
    g.home_team_id,
    g.away_team_id,
    p.picked_team_id,
    p.spread_team_id_at_lock,
    p.spread_value_at_lock,
    p.weight
  ) as gp
  where w.season_id = p_season_id
    and (g.final_scores->>'home') is not null
    and (g.final_scores->>'away') is not null
  on conflict (user_id, game_id)
  do update set
    pick_id      = excluded.pick_id,
    points_delta = excluded.points_delta,
    outcome      = excluded.outcome,
    graded_at    = excluded.graded_at;

  -- (2) Penalties for missed picks on final games
  insert into public.pick_settlement (user_id, game_id, pick_id, points_delta, outcome, graded_at)
  select
    u.id,
    g.id,
    null,
    coalesce(w.missed_pick_penalty, s.missed_pick_penalty, st.missed_pick_penalty, -1) as penalty,
    'missed'::public.pick_outcome,
    now()
  from public.weeks   w
  join public.games   g on g.week_id = w.id
  cross join (select id from public.users where role = 'player') u
  left join public.picks p on p.game_id = g.id and p.user_id = u.id
  join public.seasons s on s.id = w.season_id
  cross join public.settings st
  where w.season_id = p_season_id
    and (g.final_scores->>'home') is not null
    and (g.final_scores->>'away') is not null
    and p.id is null
  on conflict (user_id, game_id)
  do update set
    pick_id      = case when pick_settlement.pick_id is null then excluded.pick_id else pick_settlement.pick_id end,
    points_delta = case when pick_settlement.pick_id is null then excluded.points_delta else pick_settlement.points_delta end,
    outcome      = case when pick_settlement.pick_id is null then excluded.outcome else pick_settlement.outcome end,
    graded_at    = case when pick_settlement.pick_id is null then excluded.graded_at else pick_settlement.graded_at end;
end;
$$;

-- file: functions/grade/grade_week.sql
create or replace function public.grade_week(p_week_id int)
returns void
language plpgsql
security definer
set search_path = public
as $$
begin
  -- (1) Upsert settlements for real picks on final games
  insert into public.pick_settlement (user_id, game_id, pick_id, points_delta, outcome, graded_at)
  select
    p.user_id,
    g.id,
    p.id,
    gp.points_delta,
    gp.outcome,
    now()
  from public.games g
  join public.picks p on p.game_id = g.id
  cross join lateral public.grade_pick(
    (g.final_scores->>'home')::int,
    (g.final_scores->>'away')::int,
    g.home_team_id,
    g.away_team_id,
    p.picked_team_id,
    p.spread_team_id_at_lock,
    p.spread_value_at_lock,
    p.weight
  ) as gp
  where g.week_id = p_week_id
    and (g.final_scores->>'home') is not null
    and (g.final_scores->>'away') is not null
  on conflict (user_id, game_id)
  do update set
    pick_id      = excluded.pick_id,
    points_delta = excluded.points_delta,
    outcome      = excluded.outcome,
    graded_at    = excluded.graded_at;

  -- (2) Penalties for missed picks on final games (resolve per-game penalty inline)
  insert into public.pick_settlement (user_id, game_id, pick_id, points_delta, outcome, graded_at)
  select
    u.id,
    g.id,
    null,
    coalesce(w.missed_pick_penalty, s.missed_pick_penalty, st.missed_pick_penalty, -1) as penalty,
    'missed'::public.pick_outcome,
    now()
  from public.games g
  join public.weeks   w  on w.id = g.week_id
  join public.seasons s  on s.id = w.season_id
  cross join public.settings st
  cross join (select id from public.users where role = 'player') u
  left join public.picks p on p.game_id = g.id and p.user_id = u.id
  where g.week_id = p_week_id
    and (g.final_scores->>'home') is not null
    and (g.final_scores->>'away') is not null
    and p.id is null
  on conflict (user_id, game_id)
  do update set
    pick_id      = case when pick_settlement.pick_id is null then excluded.pick_id else pick_settlement.pick_id end,
    points_delta = case when pick_settlement.pick_id is null then excluded.points_delta else pick_settlement.points_delta end,
    outcome      = case when pick_settlement.pick_id is null then excluded.outcome else pick_settlement.outcome end,
    graded_at    = case when pick_settlement.pick_id is null then excluded.graded_at else pick_settlement.graded_at end;
end;
$$;
